/**
 * Audit Trail Generator - Hybrid Progressive Recording
 *
 * Implements the hybrid approach from AUDIT_TRAIL_PLAN.md:
 * - Progressive recording: Call recordStage() after EACH stage completes
 * - Partial trace resilience: If pipeline crashes at stage 5, stages 1-4 are already recorded
 * - Final aggregation: Call finalize() after all stages complete for validation and summary
 * - Failure context: Call recordFailure() if pipeline crashes to add error details
 *
 * This approach combines the benefits of incremental mutation (partial traces on failure)
 * with the benefits of end aggregation (clean separation of concerns, validation).
 */

import { ClassificationResult } from '../types/classification-result';
import { ClassificationSession } from '../types/classification-session';
import { CategoryConfiguration } from '../types/category-configuration';
import { StageName, PIPELINE_STAGE_ORDER } from '../types/stage-name';
import {
  HardAssertionResult,
  StrongIndicatorResult,
  CategoryRuleResult,
  AttributeDetectionResult,
  AttributeInfluenceResult,
  DisambiguationResult,
  MultiLabelResult,
  AIRoutingResult,
} from '../types/explainability-trace';

/**
 * Audit Trail Generator Class
 *
 * Progressively records stage results into explainability trace
 * with final aggregation and validation.
 */
export class AuditTrailGenerator {
  private readonly config: CategoryConfiguration;

  constructor(config: CategoryConfiguration) {
    this.config = config;
  }

  /**
   * Record a single stage's results into the explainability trace
   *
   * Called by pipeline after EACH stage completes.
   * Updates result.explainabilityTrace progressively.
   *
   * @param stageName - Name of the stage that just completed
   * @param result - Classification result (mutated in place)
   * @param session - Classification session context
   */
  recordStage(stageName: StageName, result: ClassificationResult, _session: ClassificationSession): void {
    // Extract stage-specific data from result fields
    const stageData = this.extractStageData(stageName, result);

    // Update explainability trace with stage results
    switch (stageName) {
      case 'hardAssertions':
        result.explainabilityTrace.hardAssertions = stageData as HardAssertionResult[];
        result.explainabilityTrace.configurationRefs['hardAssertions'] = 'categorySignals.*.hardAssertions';
        break;

      case 'strongIndicators':
        result.explainabilityTrace.strongIndicators = stageData as StrongIndicatorResult[];
        result.explainabilityTrace.configurationRefs['strongIndicators'] = 'categorySignals.*.strongIndicators';
        break;

      case 'ruleScoring':
        result.explainabilityTrace.ruleScoring = stageData as CategoryRuleResult[];
        result.explainabilityTrace.configurationRefs['ruleScoring'] = 'categorySignals.*.subtypes';
        break;

      case 'attributeDetection':
        result.explainabilityTrace.attributeDetection = stageData as AttributeDetectionResult[];
        result.explainabilityTrace.configurationRefs['attributeDetection'] = 'attributes';
        break;

      case 'attributeInfluence':
        result.explainabilityTrace.attributeInfluence = stageData as AttributeInfluenceResult[];
        result.explainabilityTrace.configurationRefs['attributeInfluence'] = 'categorySignals.*.attributeRelevance';
        break;

      case 'disambiguation':
        result.explainabilityTrace.disambiguation = stageData as DisambiguationResult[];
        result.explainabilityTrace.configurationRefs['disambiguation'] = 'settings.disambiguation';
        break;

      case 'multiLabelSelection':
        result.explainabilityTrace.multiLabelSelection = stageData as MultiLabelResult[];
        result.explainabilityTrace.configurationRefs['multiLabelSelection'] = 'settings.multiLabelSelection';
        break;

      case 'aiPipeline':
        result.explainabilityTrace.aiRouting = stageData as AIRoutingResult;
        result.explainabilityTrace.configurationRefs['aiPipeline'] = 'ai';
        break;

      case 'actionDetermination':
        // Action determination results are stored in result.finalClassificationSummary
        // and result.determinedActions, not in explainabilityTrace
        break;

      default:
        // TypeScript exhaustiveness check
        const _exhaustive: never = stageName;
        throw new Error(`Unknown stage name: ${_exhaustive}`);
    }

    // Record stage timing if available
    const timing = this.extractStageTiming(stageName, result);
    if (timing !== undefined) {
      result.explainabilityTrace.stageTimings[stageName] = timing;
    }

    // Validate stage result structure
    this.validateStageResult(stageName, stageData);
  }

  /**
   * Finalize the explainability trace after all stages complete
   *
   * Called by pipeline after ALL 9 stages complete successfully.
   * Validates completeness and aggregates final summary fields.
   *
   * @param result - Classification result with all stages recorded
   * @param session - Classification session context
   * @throws {Error} If required stages are missing
   */
  finalize(result: ClassificationResult, _session: ClassificationSession): void {
    // Validate all required stages are present
    this.validateTraceCompleteness(result);

    // Generate final decision reason from all stages
    result.explainabilityTrace.finalDecisionReason = this.synthesizeFinalReason(result);

    // Calculate total processing duration from stage timings
    const totalDurationMs = Object.values(result.explainabilityTrace.stageTimings).reduce(
      (sum, timing) => sum + timing,
      0
    );

    // Store in explainability trace (though it's also on result.processingDurationMs)
    if (totalDurationMs > 0) {
      // Only update if we have valid timings
      result.processingDurationMs = totalDurationMs;
    }

    // Aggregate alternative categories from multi-label selection
    result.explainabilityTrace.alternativeCategories = this.aggregateAlternatives(result);
  }

  /**
   * Record failure context if pipeline crashes mid-execution
   *
   * Called by pipeline if ANY stage crashes.
   * Adds failure context to partial trace for debugging.
   *
   * @param result - Classification result with partial trace
   * @param session - Classification session context
   * @param error - Error that caused the failure
   */
  recordFailure(result: ClassificationResult, session: ClassificationSession, error: Error): void {
    // Mark trace as partial
    const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
    trace.partialResults = true;

    // Detect which stage failed based on what's present
    trace.failedStage = this.detectFailedStage(result);

    // Add error context
    trace.errorMessage = error.message;
    trace.errorStack = error.stack;
  }

  /**
   * Extract stage-specific data from result object
   *
   * @param stageName - Stage to extract data from
   * @param result - Classification result
   * @returns Stage-specific data
   */
  private extractStageData(
    stageName: StageName,
    result: ClassificationResult
  ):
    | HardAssertionResult[]
    | StrongIndicatorResult[]
    | CategoryRuleResult[]
    | AttributeDetectionResult[]
    | AttributeInfluenceResult[]
    | DisambiguationResult[]
    | MultiLabelResult[]
    | AIRoutingResult
    | unknown {
    // For now, stages still populate explainabilityTrace directly
    // This method will be fully implemented when we remove direct mutations (Phase 3 of refactoring)
    switch (stageName) {
      case 'hardAssertions':
        return result.explainabilityTrace.hardAssertions || [];
      case 'strongIndicators':
        return result.explainabilityTrace.strongIndicators || [];
      case 'ruleScoring':
        return result.explainabilityTrace.ruleScoring || [];
      case 'attributeDetection':
        return result.explainabilityTrace.attributeDetection || [];
      case 'attributeInfluence':
        return result.explainabilityTrace.attributeInfluence || [];
      case 'disambiguation':
        return result.explainabilityTrace.disambiguation || [];
      case 'multiLabelSelection':
        return result.explainabilityTrace.multiLabelSelection || [];
      case 'aiPipeline':
        return result.explainabilityTrace.aiRouting;
      case 'actionDetermination':
        return {};
      default:
        const _exhaustive: never = stageName;
        throw new Error(`Unknown stage name: ${_exhaustive}`);
    }
  }

  /**
   * Extract stage timing from result
   *
   * @param stageName - Stage to get timing for
   * @param result - Classification result
   * @returns Duration in milliseconds, or undefined if not recorded
   */
  private extractStageTiming(stageName: StageName, result: ClassificationResult): number | undefined {
    return result.explainabilityTrace.stageTimings[stageName];
  }

  /**
   * Validate stage result structure
   *
   * @param stageName - Stage that was recorded
   * @param stageData - Data to validate
   * @throws {Error} If stage data is malformed
   */
  private validateStageResult(stageName: StageName, stageData: unknown): void {
    // Basic validation - can be expanded with Zod schemas if needed
    if (stageData === undefined || stageData === null) {
      throw new Error(`Stage ${stageName} produced undefined/null data`);
    }

    // Array stages should return arrays
    const arrayStages: StageName[] = [
      'hardAssertions',
      'strongIndicators',
      'ruleScoring',
      'attributeDetection',
      'attributeInfluence',
      'disambiguation',
      'multiLabelSelection',
    ];

    if (arrayStages.includes(stageName) && !Array.isArray(stageData)) {
      throw new Error(`Stage ${stageName} should return array, got ${typeof stageData}`);
    }
  }

  /**
   * Validate that all required stages are present in the trace
   *
   * @param result - Classification result to validate
   * @throws {Error} If required stages are missing
   */
  private validateTraceCompleteness(result: ClassificationResult): void {
    const requiredStages: StageName[] = [
      'hardAssertions',
      'strongIndicators',
      'ruleScoring',
      'attributeDetection',
      'attributeInfluence',
      'disambiguation',
      'multiLabelSelection',
      'aiPipeline',
      'actionDetermination',
    ];

    const trace = result.explainabilityTrace;
    const missingStages: string[] = [];

    // Check each required stage
    for (const stage of requiredStages) {
      switch (stage) {
        case 'hardAssertions':
          if (!trace.hardAssertions || trace.hardAssertions.length === 0) {
            // Hard assertions can be empty if no matches, but should exist
            if (!trace.hardAssertions) missingStages.push(stage);
          }
          break;
        case 'strongIndicators':
          if (!trace.strongIndicators) missingStages.push(stage);
          break;
        case 'ruleScoring':
          if (!trace.ruleScoring) missingStages.push(stage);
          break;
        case 'attributeDetection':
          if (!trace.attributeDetection) missingStages.push(stage);
          break;
        case 'attributeInfluence':
          if (!trace.attributeInfluence) missingStages.push(stage);
          break;
        case 'disambiguation':
          if (!trace.disambiguation) missingStages.push(stage);
          break;
        case 'multiLabelSelection':
          if (!trace.multiLabelSelection) missingStages.push(stage);
          break;
        case 'aiPipeline':
          // AI pipeline is optional - only required if AI classification was used
          if (result.aiRoutingUsed && !trace.aiRouting) {
            missingStages.push(stage);
          }
          break;
        case 'actionDetermination':
          // Action determination results are in result.finalClassificationSummary
          if (!result.finalClassificationSummary) missingStages.push(stage);
          break;
      }
    }

    if (missingStages.length > 0) {
      throw new Error(`Incomplete audit trail: missing stages ${missingStages.join(', ')}`);
    }
  }

  /**
   * Synthesize final decision reason from all stage results
   *
   * @param result - Classification result with all stages
   * @returns Human-readable summary of classification decision
   */
  private synthesizeFinalReason(result: ClassificationResult): string {
    const reasons: string[] = [];

    // Use finalClassificationSummary if available (from action determination stage)
    if (result.finalClassificationSummary) {
      const summary = result.finalClassificationSummary;
      reasons.push(
        `Primary Category: ${summary.primaryCategory}${summary.primarySubtype ? ` (${summary.primarySubtype})` : ''}`
      );
      reasons.push(`Confidence: ${(summary.confidenceRange[1] * 100).toFixed(1)}%`);
      reasons.push(`Classification Path: ${summary.classificationPath}`);

      if (summary.selectedLabels.length > 1) {
        reasons.push(`Multi-label: ${summary.selectedLabels.length} categories selected`);
      }

      if (summary.determinedActions.length > 0) {
        reasons.push(`Actions: ${summary.determinedActions.join(', ')}`);
      }
    } else {
      // Fallback if finalClassificationSummary not available
      reasons.push(`Primary Category: ${result.primaryCategory}`);
      reasons.push(`Confidence: ${(result.confidence * 100).toFixed(1)}%`);
    }

    // Add stage-specific insights
    if (result.explainabilityTrace.hardAssertions.length > 0) {
      reasons.push(`Hard Assertion: ${result.explainabilityTrace.hardAssertions[0].reason || 'Domain-based match'}`);
    }

    if (result.explainabilityTrace.aiRouting) {
      const aiResult = result.explainabilityTrace.aiRouting;
      reasons.push(`AI Routing: ${aiResult.routingDecision}`);
    }

    return reasons.join(' | ');
  }

  /**
   * Aggregate alternative categories from multi-label selection
   *
   * @param result - Classification result
   * @returns Array of alternative categories with elimination reasons
   */
  private aggregateAlternatives(
    result: ClassificationResult
  ): Array<{ category: string; score: number; eliminationReason: string }> {
    const alternatives: Array<{ category: string; score: number; eliminationReason: string }> = [];

    // Extract from multi-label selection results
    if (result.explainabilityTrace.multiLabelSelection && result.explainabilityTrace.multiLabelSelection.length > 0) {
      const multiLabel = result.explainabilityTrace.multiLabelSelection[0];
      if (multiLabel.rejectedCategories) {
        alternatives.push(
          ...multiLabel.rejectedCategories.map((r) => ({
            category: r.category,
            score: r.score,
            eliminationReason: r.rejectionReason,
          }))
        );
      }
    }

    // Also include candidates from candidateScores that weren't selected
    if (result.candidateScores) {
      const selectedCategories = new Set(result.selectedLabels.map((l) => l.category));
      for (const [category, scoreInfo] of Object.entries(result.candidateScores)) {
        if (!selectedCategories.has(category) && scoreInfo.decision === 'rejected') {
          alternatives.push({
            category,
            score: scoreInfo.score,
            eliminationReason: scoreInfo.rationale || 'Below confidence threshold',
          });
        }
      }
    }

    // Deduplicate by category (prefer multi-label rejection reasons)
    const seen = new Set<string>();
    return alternatives.filter((alt) => {
      if (seen.has(alt.category)) return false;
      seen.add(alt.category);
      return true;
    });
  }

  /**
   * Detect which stage failed based on what stages are present
   *
   * @param result - Classification result with partial trace
   * @returns Name of the stage that likely failed
   */
  private detectFailedStage(result: ClassificationResult): string {
    const trace = result.explainabilityTrace;
    const completedStages: string[] = [];

    // Check which stages have been recorded
    if (trace.hardAssertions) completedStages.push('hardAssertions');
    if (trace.strongIndicators) completedStages.push('strongIndicators');
    if (trace.ruleScoring) completedStages.push('ruleScoring');
    if (trace.attributeDetection) completedStages.push('attributeDetection');
    if (trace.attributeInfluence) completedStages.push('attributeInfluence');
    if (trace.disambiguation) completedStages.push('disambiguation');
    if (trace.multiLabelSelection) completedStages.push('multiLabelSelection');
    if (trace.aiRouting) completedStages.push('aiPipeline');
    if (result.finalClassificationSummary) completedStages.push('actionDetermination');

    // The failed stage is the next one after the last completed
    if (completedStages.length === 0) {
      return 'hardAssertions (initialization failure)';
    }

    const lastCompleted = completedStages[completedStages.length - 1];
    const lastIndex = PIPELINE_STAGE_ORDER.findIndex((s) => s === lastCompleted);

    if (lastIndex === -1 || lastIndex === PIPELINE_STAGE_ORDER.length - 1) {
      return `${lastCompleted} (or post-processing)`;
    }

    return PIPELINE_STAGE_ORDER[lastIndex + 1];
  }
}

