/**
 * Classification Pipeline Orchestrator
 *
 * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
 * (email, session, result, config) => void
 *
 * Pipeline Stages:
 * 1. Hard Assertions - Domain-based high-confidence categorization
 * 2. Strong Indicators - Weighted seed scoring with diminishing returns
 * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
 * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
 * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
 * 6. Disambiguation - Pairwise conflict resolution for close scores
 * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
 * 8. AI Routing - Selective AI classification for uncertain cases
 * 9. Final Decision - Label assignment and action determination
 * 10. Audit Trail - Complete explainability trace generation
 */

import { CategoryConfiguration } from '../types/category-configuration';
import { ClassificationResult } from '../types/classification-result';
import { ClassificationSession } from '../types/classification-session';
import { EmailMessage } from '../types/email-message';

// Validation utilities
import { validateConfigInput, validateEmailInput } from '../utils/validation';

// Domain lookup loader
import { DomainLookup, loadDomainLookup } from '../config/domain-resolver';

// Audit trail generator
import { AuditTrailGenerator } from '../audit-trail/audit-trail-generator';

// Initialization utilities
import {
  createClassificationResult,
  createClassificationSession,
  finalizeClassificationSession,
  incrementSessionError,
  incrementSessionSuccess,
} from '../utils/initialization';

// Pipeline stages (canonical signatures)
import { actionDeterminationStage } from '../stages/action-determination';
import { aiClassificationStage } from '../stages/ai-classification';
import { aiFeatureExtractionStage } from '../stages/ai-feature-extraction';
import { aiLabelFilteringStage } from '../stages/ai-label-filtering';
import { aiRoutingStage } from '../stages/ai-routing';
import { executeAttributeDetection } from '../stages/attribute-detection';
import { executeAttributeInfluence } from '../stages/attribute-influence';
import { executeDisambiguation } from '../stages/disambiguation';
import { executeHardAssertions } from '../stages/hard-assertions';
import { executeMultiLabelSelection } from '../stages/multi-label-selection';
import { executeRuleScoring } from '../stages/rule-scoring';
import { executeStrongIndicators } from '../stages/strong-indicators';
// import { generateAuditTrail } from '../stages/audit-trail'; // TODO (T052): Wire audit trail after PipelineOutput/ClassificationResult architectural refactoring decision (see T052 re-evaluation criteria in tasks.md)

// Stage-specific config types
import type { ActionDeterminationConfig } from '../stages/action-determination';
import type { AIClassificationConfig } from '../stages/ai-classification';
import type { AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
import type { AILabelFilteringConfig } from '../stages/ai-label-filtering';
import type { AIRoutingConfig } from '../stages/ai-routing';
import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
import type { HardAssertionStageConfig } from '../stages/hard-assertions';
import type { RuleScoringStageConfig } from '../stages/rule-scoring';
import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
import type { ConfidenceThresholds, MultiLabelConfig } from '../stages/types';
// import type { AuditTrailConfig } from '../stages/audit-trail'; // TODO (T052): Wire audit trail config after PipelineOutput/ClassificationResult architectural refactoring decision (see T052 re-evaluation criteria in tasks.md)

/**
 * Pipeline stage execution order for replay functionality
 */
const STAGE_ORDER = [
  'hard-assertions',
  'strong-indicators',
  'rule-scoring',
  'attribute-detection',
  'attribute-influence',
  'disambiguation',
  'multi-label-selection',
  'ai-routing',
  'ai-feature-extraction',
  'ai-classification',
  'ai-label-filtering',
  'action-determination',
] as const;

/**
 * Stage task interface for replay-from-stage support
 *
 * Wraps individual pipeline stage functions to enable selective execution
 * based on replay parameters while maintaining minimal disruption to existing code.
 */
interface StageTask {
  /**
   * Stage identifier for replay functionality
   */
  name: string;

  /**
   * Execute the stage with canonical signature pattern
   *
   * @param email - Email message to process
   * @param session - Classification session context
   * @param result - Mutable classification result (modified in place)
   * @param config - Stage-specific configuration
   */
  execute(
    email: EmailMessage,
    session: ClassificationSession,
    result: ClassificationResult,
    config: CategoryConfiguration
  ): Promise<void>;

  /**
   * Determine if this stage should be skipped for replay functionality
   *
   * @param replayFromStage - Optional stage to start replay from
   * @returns true if stage should be skipped, false to execute
   */
  shouldSkip(replayFromStage?: string): boolean;
}

/**
 * Error result for batch processing when individual email fails
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

/**
 * Classification Pipeline orchestrator
 *
 * Manages sequential execution of classification stages with proper context
 * propagation, error handling, and performance tracking.
 */
export class ClassificationPipeline {
  private readonly config: CategoryConfiguration;
  private readonly testMode: boolean;
  private readonly domainLookup: DomainLookup;
  private readonly auditTrail: AuditTrailGenerator;

  /**
   * Initialize classification pipeline with validated configuration
   *
   * @param config - Complete category configuration including processingConfig
   * @param testMode - If true, use timestamp-based session IDs for easier debugging
   * @throws {Error} If configuration validation fails
   */
  constructor(config: CategoryConfiguration, testMode: boolean = false) {
    // Validate processing configuration exists
    validateConfigInput(config.processingConfig);

    // Check for deprecated/invalid config properties (defensive runtime validation)
    const processingConfigAny = config.processingConfig as Record<string, unknown>;
    if ('confidenceThresholds' in processingConfigAny) {
      throw new Error(
        'Configuration validation failed: confidenceThresholds is deprecated (use settings.multiLabelSelection instead)'
      );
    }

    // Validate required config properties are present (defensive runtime validation)
    if (!config.processingConfig.settings) {
      throw new Error('Configuration validation failed: settings is required');
    }
    if (!config.processingConfig.settings.multiLabelSelection) {
      throw new Error('Configuration validation failed: settings.multiLabelSelection is required');
    }

    // Validate multi-label selection thresholds
    const multiLabelSettings = config.processingConfig.settings.multiLabelSelection;
    if (
      !multiLabelSettings ||
      multiLabelSettings.highConfidenceThreshold < 0 ||
      multiLabelSettings.mediumConfidenceThreshold < 0 ||
      multiLabelSettings.lowConfidenceThreshold < 0 ||
      multiLabelSettings.secondaryLabelMinGap < 0
    ) {
      throw new Error('Invalid multi-label selection thresholds: all values must be non-negative');
    }

    this.config = config;
    this.testMode = testMode;

    // Load domain lookup from config/domain-sources.json
    // Gracefully handles missing/malformed files by returning empty lookup
    this.domainLookup = loadDomainLookup();

    // Initialize audit trail generator for progressive recording
    this.auditTrail = new AuditTrailGenerator(config);
  }

  /**
   * Get configuration (for testing and future stage integration)
   */
  getConfig(): CategoryConfiguration {
    return this.config;
  }

  /**
   * Helper function to determine if a stage should be skipped for replay
   *
   * @param stageName - Name of the current stage
   * @param replayFromStage - Stage to start replay from (optional)
   * @returns true if stage should be skipped, false to execute
   */
  private shouldSkipStage(stageName: string, replayFromStage?: string): boolean {
    if (!replayFromStage) return false;
    const replayIndex = STAGE_ORDER.indexOf(replayFromStage as (typeof STAGE_ORDER)[number]);
    const currentIndex = STAGE_ORDER.indexOf(stageName as (typeof STAGE_ORDER)[number]);
    return replayIndex !== -1 && currentIndex < replayIndex;
  }

  /**
   * Stage configuration mapping for factory pattern
   */
  private readonly stageConfigs = {
    'hard-assertions': () => this.getHardAssertionConfig(),
    'strong-indicators': () => this.getStrongIndicatorConfig(),
    'rule-scoring': () => this.getRuleScoringConfig(),
    'attribute-detection': () => this.getAttributeDetectionConfig(),
    'attribute-influence': () => this.config,
    disambiguation: () => this.config,
    'multi-label-selection': () => ({
      multiLabel: this.getMultiLabelConfig(),
      confidenceThresholds: this.getConfidenceThresholds(),
    }),
    'ai-routing': () => this.getAIRoutingConfig(),
    'ai-feature-extraction': () => this.getAIFeatureExtractionConfig(),
    'ai-classification': () => this.getAIClassificationConfig(),
    'ai-label-filtering': () => this.getAILabelFilteringConfig(),
    'action-determination': () => this.getActionDeterminationConfig(),
  } as const;

  /**
   * Stage function mapping for factory pattern
   */
  private readonly stageFunctions = {
    'hard-assertions': executeHardAssertions,
    'strong-indicators': executeStrongIndicators,
    'rule-scoring': executeRuleScoring,
    'attribute-detection': executeAttributeDetection,
    'attribute-influence': executeAttributeInfluence,
    disambiguation: executeDisambiguation,
    'multi-label-selection': (
      email: EmailMessage,
      session: ClassificationSession,
      result: ClassificationResult,
      config: { multiLabel: MultiLabelConfig; confidenceThresholds: ConfidenceThresholds }
    ) => {
      executeMultiLabelSelection(email, session, result, config.multiLabel, config.confidenceThresholds);
    },
    'ai-routing': aiRoutingStage,
    'ai-feature-extraction': aiFeatureExtractionStage,
    'ai-classification': aiClassificationStage,
    'ai-label-filtering': aiLabelFilteringStage,
    'action-determination': actionDeterminationStage,
  } as const;

  /**
   * Conditional execution for AI stages
   */
  private readonly conditionalStages = new Set(['ai-feature-extraction', 'ai-classification', 'ai-label-filtering']);

  /**
   * Create a single stage task using factory pattern
   */
  private createStageTask(stageName: keyof typeof this.stageConfigs): StageTask {
    return {
      name: stageName,
      execute: async (email, session, result, _config) => {
        // Check if this is a conditional AI stage
        if (this.conditionalStages.has(stageName) && !result.needsAiClassification) {
          return;
        }

        const stageConfig = this.stageConfigs[stageName]();
        const stageFunction = this.stageFunctions[stageName];
        await stageFunction(email, session, result, stageConfig as never);
      },
      shouldSkip: (replayFromStage) => this.shouldSkipStage(stageName, replayFromStage),
    };
  }

  /**
   * Create ordered array of stage tasks using factory pattern
   *
   * Each stage task wraps existing stage functions with replay logic
   * while preserving canonical signatures and conditional execution.
   *
   * @returns Array of stage tasks in execution order
   */
  private createStageTasks(): StageTask[] {
    return STAGE_ORDER.map((stageName) => this.createStageTask(stageName));
  }

  /**
   * Map stage task names (kebab-case) to StageName (camelCase)
   */
  private mapToStageName(taskName: string): import('../types/stage-name').StageName | null {
    const mapping: Record<string, import('../types/stage-name').StageName> = {
      'hard-assertions': 'hardAssertions',
      'strong-indicators': 'strongIndicators',
      'rule-scoring': 'ruleScoring',
      'attribute-detection': 'attributeDetection',
      'attribute-influence': 'attributeInfluence',
      disambiguation: 'disambiguation',
      'multi-label-selection': 'multiLabelSelection',
      'ai-routing': 'aiPipeline',
      'ai-feature-extraction': 'aiPipeline',
      'ai-classification': 'aiPipeline',
      'ai-label-filtering': 'aiPipeline',
      'action-determination': 'actionDetermination',
    };
    return mapping[taskName] || null;
  }

  /**
   * Core pipeline execution logic shared by both classify methods
   */
  private async executePipelineStages(
    email: EmailMessage,
    session: ClassificationSession,
    result: ClassificationResult,
    pipelineStartTime: number,
    replayFromStage?: string
  ): Promise<void> {
    // Get stage tasks array
    const stageTasks = this.createStageTasks();

    try {
      // Execute stages using StageTask architecture
      for (const stageTask of stageTasks) {
        // Check if this stage should be skipped for replay
        if (stageTask.shouldSkip(replayFromStage)) {
          if (this.testMode && replayFromStage) {
            console.log(`Skipping stage: ${stageTask.name} (replay from: ${replayFromStage})`);
          }
          continue;
        }

        // Log stage execution only in test mode
        if (this.testMode) {
          console.log(`Executing stage: ${stageTask.name}`);
        }

        // Execute the stage with unified error handling
        try {
          await stageTask.execute(email, session, result, this.config);

          // Record stage result in audit trail (progressive recording)
          // Map AI sub-stages to single 'aiPipeline' stage name
          const stageName = this.mapToStageName(stageTask.name);
          if (stageName) {
            // Only record once for AI pipeline (after ai-label-filtering completes)
            if (stageName === 'aiPipeline' && stageTask.name !== 'ai-label-filtering') {
              // Skip recording for intermediate AI stages
              continue;
            }
            this.auditTrail.recordStage(stageName, result, session);
          }
        } catch (error) {
          // Record partial trace before throwing
          this.auditTrail.recordFailure(result, session, error instanceof Error ? error : new Error(String(error)));
          throw new Error(
            `Stage '${stageTask.name}' failed: ${error instanceof Error ? error.message : String(error)}`
          );
        }
      }

      // All stages completed successfully - finalize audit trail
      this.auditTrail.finalize(result, session);
    } catch (error) {
      // Error already recorded by recordFailure() above, just re-throw
      throw error;
    }
  }

  /**
   * Unified error handling for pipeline failures
   */
  private createPipelineError(email: EmailMessage, startTime: number, error: unknown): Error {
    const endTime = Date.now();
    const message = error instanceof Error ? error.message : String(error);
    return new Error(`Classification pipeline failed for email ${email.id} after ${endTime - startTime}ms: ${message}`);
  }

  /**
   * Execute classification pipeline using StageTask architecture with optional replay support
   *
   * Provides the foundation for true replay-from-stage functionality by iterating
   * through stage tasks and selectively skipping stages based on replay parameters.
   *
   * @param email - Email message to classify
   * @param replayFromStage - Optional stage name to start replay from
   * @returns Complete classification result with selected labels
   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   */
  async classifyWithStageTask(email: EmailMessage, replayFromStage?: string): Promise<ClassificationResult> {
    const pipelineStartTime = Date.now();

    try {
      // Validate email input
      validateEmailInput(email);

      // Create classification session for single email
      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);

      // Create classification result
      const result = createClassificationResult(email.id, session.id, 0);

      // Execute pipeline stages using shared logic
      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);

      // Mark session as successful
      incrementSessionSuccess(session);
      finalizeClassificationSession(session);

      // Update final processing time
      result.processingDurationMs = Date.now() - pipelineStartTime;
      result.processedAt = new Date();

      return result;
    } catch (error) {
      throw this.createPipelineError(email, pipelineStartTime, error);
    }
  }

  /**
   * Execute classification pipeline using provided session (for batch processing)
   *
   * Uses an externally-created session to enable multiple emails to share the same
   * sessionId. This is essential for batch processing where all emails should be
   * grouped under one session for traceability.
   *
   * @param email - Email message to classify
   * @param session - Existing classification session to use
   * @param batchPosition - Position of email in batch (for result metadata)
   * @param replayFromStage - Optional stage name to start replay from
   * @returns Complete classification result with selected labels
   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   */
  async classifyWithSession(
    email: EmailMessage,
    session: ClassificationSession,
    batchPosition: number = 0,
    replayFromStage?: string
  ): Promise<ClassificationResult> {
    const pipelineStartTime = Date.now();

    try {
      // Validate email input
      validateEmailInput(email);

      // Create classification result using provided session
      const result = createClassificationResult(email.id, session.id, batchPosition);

      // Execute pipeline stages using shared logic
      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);

      // Update final processing time
      result.processingDurationMs = Date.now() - pipelineStartTime;
      result.processedAt = new Date();

      return result;
    } catch (error) {
      throw this.createPipelineError(email, pipelineStartTime, error);
    }
  }

  /**
   * Shared configuration composition helpers
   */
  private getBaseStageConfig() {
    return {
      // Type assertion: CategorySignals structure is compatible with stage-specific signal configs
      categorySignals: this.config.processingConfig.categorySignals as Record<string, never>,
      domainLookup: this.domainLookup,
    };
  }

  private getOpenAIConfig(requiredFor: string) {
    const openaiApiKey = process.env.OPENAI_API_KEY || '';
    if (!openaiApiKey) {
      throw new Error(`OPENAI_API_KEY environment variable is required for ${requiredFor}`);
    }
    return {
      apiKey: openaiApiKey,
      model: 'gpt-4o-mini',
      temperature: 0.0,
      responseFormat: 'json_schema' as const,
    };
  }

  private getRetryPolicy() {
    return {
      maxRetries: 3,
      backoffMs: 1000,
    };
  }

  /**
   * Extract configuration for hard assertions stage
   */
  private getHardAssertionConfig(): HardAssertionStageConfig {
    const settings = this.config.processingConfig.settings;
    return {
      ...this.getBaseStageConfig(),
      hardAssertionsSettings: settings.hardAssertions || { confidenceFloor: 1.0 },
    };
  }

  /**
   * Extract configuration for strong indicators stage
   */
  private getStrongIndicatorConfig(): StrongIndicatorStageConfig {
    const settings = this.config.processingConfig.settings;
    return {
      ...this.getBaseStageConfig(),
      strongIndicatorBaseWeight: settings.strongIndicators?.baseWeight ?? 10,
      diminishingReturnsFactor: settings.strongIndicators?.diminishingReturnsFactor ?? 0.5,
    };
  }

  /**
   * Extract configuration for rule scoring stage
   */
  private getRuleScoringConfig(): RuleScoringStageConfig {
    const tuningParams = this.config.processingConfig.settings.ruleScoring.tuningParameters;
    return {
      topLevelCategories: this.config.processingConfig.topLevelCategories,
      settings: this.config.processingConfig.settings.ruleScoring,
      tuningParameters: {
        // Map config values (KHigh, KMedium, KLow) to internal names
        // These are multipliers applied to sum of ALL tier weights (not topK limits)
        KHigh: tuningParams?.KHigh ?? 1,
        KMedium: tuningParams?.KMedium ?? 0.7,
        KLow: tuningParams?.KLow ?? 0.3,
        // TAIL_DAMPEN and TAIL_RATIO_CAP control score aggregation behavior
        // Use conservative defaults if not specified in config
        TAIL_DAMPEN: 0.5,
        TAIL_RATIO_CAP: 0.25,
        aggregationCap: tuningParams?.aggregationCap ?? 1.0,
      },
    };
  }

  /**
   * Extract configuration for attribute detection stage
   */
  private getAttributeDetectionConfig(): AttributeDetectionStageConfig {
    return {
      attributes: this.config.processingConfig.attributes,
      settings: {
        attributeProcessing: this.config.processingConfig.settings.attributeProcessing,
      },
      performanceCache: {}, // Optional performance cache for domain lookups
    };
  }

  /**
   * Extract configuration for multi-label selection stage
   */
  private getMultiLabelConfig(): MultiLabelConfig {
    const settings = this.config.processingConfig.settings.multiLabelSelection;
    return {
      maxLabels: settings.maxLabels,
      highConfidenceThreshold: settings.highConfidenceThreshold,
      mediumConfidenceThreshold: settings.mediumConfidenceThreshold,
      lowConfidenceThreshold: settings.lowConfidenceThreshold,
      secondaryLabelMinGap: settings.secondaryLabelMinGap,
      allowedCombinations: settings.allowedCombinations,
      strictCombinationMode: settings.strictCombinationMode,
    };
  }

  /**
   * Get confidence thresholds (for backward compatibility)
   */
  private getConfidenceThresholds(): ConfidenceThresholds {
    const settings = this.config.processingConfig.settings.multiLabelSelection;
    return {
      highConfidenceThreshold: settings.highConfidenceThreshold,
      mediumConfidenceThreshold: settings.mediumConfidenceThreshold,
      lowConfidenceThreshold: settings.lowConfidenceThreshold,
      secondaryLabelMinGap: settings.secondaryLabelMinGap,
    };
  }

  /**
   * Extract configuration for AI routing stage
   */
  private getAIRoutingConfig(): AIRoutingConfig {
    return {
      settings: {
        aiRouting: this.config.processingConfig.settings.aiRouting,
      },
    };
  }

  /**
   * Extract configuration for AI feature extraction stage
   */
  private getAIFeatureExtractionConfig(): AIFeatureExtractionConfig {
    return {
      openai: this.getOpenAIConfig('AI feature extraction'),
      prompts: this.config.processingConfig.aiPrompts.featureExtraction,
      featureExtractionSchema: {
        name: 'email_feature_extraction',
        description: 'Extract semantic features from email content',
        schema: this.config.processingConfig.featureExtractionSchema as unknown as Record<string, unknown>,
        strict: true,
      },
      retryPolicy: this.getRetryPolicy(),
    };
  }

  /**
   * Extract configuration for AI classification stage
   */
  private getAIClassificationConfig(): AIClassificationConfig {
    return {
      openai: this.getOpenAIConfig('AI classification'),
      prompts: this.config.processingConfig.aiPrompts.finalClassification,
      classificationSchema: {
        name: 'email_classification',
        description: 'Classify email into categories',
        schema: {
          type: 'object',
          properties: {
            primaryCategory: { type: 'string' },
            secondaryCategories: { type: 'array', items: { type: 'string' } },
            confidence: { type: 'number' },
            reasoning: { type: 'string' },
          },
          required: ['primaryCategory', 'secondaryCategories', 'confidence', 'reasoning'],
          additionalProperties: false,
        },
        strict: true,
      },
      skipConditions: {
        highConfidenceThreshold: this.config.processingConfig.settings.aiRouting.highConfidenceThreshold,
        skipReasons: this.config.processingConfig.settings.aiRouting.skipAiConditions,
      },
      retryPolicy: this.getRetryPolicy(),
    };
  }

  /**
   * Extract configuration for AI label filtering stage
   */
  private getAILabelFilteringConfig(): AILabelFilteringConfig {
    const settings = this.config.processingConfig.settings.multiLabelSelection;
    return {
      labelAssignmentRules: {
        maxLabels: settings.maxLabels,
        minSecondaryConfidence: settings.mediumConfidenceThreshold,
        allowedCombinations: settings.allowedCombinations.map((combo) => combo.categories.join('+')),
      },
    };
  }

  /**
   * Extract configuration for action determination stage
   */
  private getActionDeterminationConfig(): ActionDeterminationConfig {
    return {
      archiveThresholds: {
        lowImportance: 0.3,
        mediumImportance: 0.5,
        highImportance: 0.7,
      },
      defaultArchiveThreshold: 'mediumImportance',
      actionSettings: {
        archiveIfBelowThreshold: true,
        markAsReadIfArchived: false,
        applyCustomActions: false,
      },
    };
  }

  /**
   * Execute classification pipeline on single email
   *
   * Uses the StageTask architecture for consistent pipeline execution.
   * This method now delegates to classifyWithStageTask for unified pipeline logic.
   *
   * @param email - Email message to classify
   * @returns Complete classification result with selected labels
   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   */
  async classify(email: EmailMessage): Promise<ClassificationResult> {
    // Delegate to StageTask architecture (no replay, execute all stages)
    return this.classifyWithStageTask(email);
  }

  /**
   * Process multiple emails sequentially with shared session context
   *
   * Uses the StageTask architecture for consistent pipeline execution.
   * Each email is processed independently using classifyWithStageTask.
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    // Create batch session for tracking
    const session = createClassificationSession(
      this.config.processingConfig,
      'sequential',
      emails.length,
      this.testMode
    );

    for (let i = 0; i < emails.length; i++) {
      const email = emails[i];
      const startTime = Date.now();
      try {
        // Use StageTask architecture for consistent pipeline execution
        const result = await this.classifyWithStageTask(email);

        // Update batch position and session tracking
        result.batchPosition = i;
        result.sessionId = session.id;
        incrementSessionSuccess(session);

        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        incrementSessionError(session, email.id, 'pipeline', error instanceof Error ? error.message : String(error));
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    // Finalize session after all emails processed
    finalizeClassificationSession(session);

    return results;
  }
}

